function initDownloads() {
    const excelBtn = document.getElementById('downloadExcel');
    const pdfBtn   = document.getElementById('downloadPdf');

    excelBtn?.addEventListener('click', () => {
        const a    = document.createElement('a');
        const date = new Date().toISOString().slice(0, 10);
        a.href     = 'downloads/lista-precios.xlsx';
        a.download = `Distrifel-Lista-de-Precios-${date}.xlsx`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
    });

    pdfBtn?.addEventListener('click', () => generatePDF());
}

/* ============================================================
   GENERADOR DE PDF
   ============================================================ */

function drawImgToCanvas(img, contain, targetW, targetH) {
    const c = document.createElement('canvas');
    c.width = targetW; c.height = targetH;
    const ctx = c.getContext('2d');
    ctx.fillStyle = '#f8fafc'; ctx.fillRect(0, 0, targetW, targetH);
    if (contain) {
        const scale = Math.min(targetW / img.naturalWidth, targetH / img.naturalHeight);
        const sw = img.naturalWidth * scale, sh = img.naturalHeight * scale;
        ctx.drawImage(img, (targetW - sw) / 2, (targetH - sh) / 2, sw, sh);
    } else {
        const scale = Math.min(targetW / img.naturalWidth, targetH / img.naturalHeight);
        const sw = img.naturalWidth * scale, sh = img.naturalHeight * scale;
        ctx.drawImage(img, (targetW - sw) / 2, (targetH - sh) / 2, sw, sh);
    }
    return c.toDataURL('image/jpeg', 0.75);
}

async function loadImgBase64(url, contain = true, targetW = 400, targetH = 300) {
    if (!url) return null;

    // Imágenes locales (img/p*.jpg) — usar Image sin crossOrigin (same-origin file://)
    const isLocal = !url.startsWith('http') && !url.startsWith('data:');
    if (isLocal) {
        return new Promise(resolve => {
            const img = new Image();
            const t = setTimeout(() => resolve(null), 5000);
            img.onload = () => {
                clearTimeout(t);
                try { resolve(drawImgToCanvas(img, contain, targetW, targetH)); }
                catch { resolve(null); }
            };
            img.onerror = () => { clearTimeout(t); resolve(null); };
            img.src = url;
        });
    }

    // Para URLs externas intentar directo con Image+crossOrigin primero (evita CORS de fetch)
    const isExternal = /^https?:\/\//.test(url) && !url.startsWith(location.origin);
    if (isExternal) {
        const result = await new Promise(resolve => {
            const img = new Image();
            img.crossOrigin = 'anonymous';
            const t = setTimeout(() => resolve(null), 6000);
            img.onload = () => {
                clearTimeout(t);
                try {
                    const c = document.createElement('canvas');
                    c.width = targetW; c.height = targetH;
                    const ctx = c.getContext('2d');
                    ctx.fillStyle = '#f8fafc'; ctx.fillRect(0,0,targetW,targetH);
                    const scale = Math.min(targetW/img.naturalWidth, targetH/img.naturalHeight);
                    const sw = img.naturalWidth*scale, sh = img.naturalHeight*scale;
                    ctx.drawImage(img,(targetW-sw)/2,(targetH-sh)/2,sw,sh);
                    resolve(c.toDataURL('image/jpeg',0.75));
                } catch { resolve(null); }
            };
            img.onerror = () => { clearTimeout(t); resolve(null); };
            img.src = url;
        });
        if (result) return result;
    }
    // Fallback: fetch (funciona para mismo origen)
    try {
        const res = await Promise.race([
            fetch(url).then(r => r.ok ? r.blob() : Promise.reject()),
            new Promise((_, rej) => setTimeout(() => rej('timeout'), 5000))
        ]);
        const base64 = await new Promise(resolve => {
            const reader = new FileReader();
            reader.onload = () => resolve(reader.result);
            reader.readAsDataURL(res);
        });
        // Dibujar en canvas con contain
        return await new Promise(resolve => {
            const img = new Image();
            img.onload = () => {
                try {
                    const c = document.createElement('canvas');
                    c.width = targetW; c.height = targetH;
                    const ctx = c.getContext('2d');
                    ctx.fillStyle = contain ? '#f8fafc' : '#111827';
                    ctx.fillRect(0, 0, targetW, targetH);
                    if (contain) {
                        const scale = Math.min(targetW / img.naturalWidth, targetH / img.naturalHeight);
                        const sw = img.naturalWidth * scale;
                        const sh = img.naturalHeight * scale;
                        ctx.drawImage(img, (targetW - sw) / 2, (targetH - sh) / 2, sw, sh);
                    } else {
                        const scale = Math.min(targetW / img.naturalWidth, targetH / img.naturalHeight);
                        const sw = img.naturalWidth * scale;
                        const sh = img.naturalHeight * scale;
                        ctx.drawImage(img, (targetW - sw) / 2, (targetH - sh) / 2, sw, sh);
                    }
                    resolve(c.toDataURL('image/jpeg', 0.75));
                } catch { resolve(null); }
            };
            img.onerror = () => resolve(null);
            img.src = base64;
        });
    } catch { return null; }
}

async function generatePDF() {
    const btn = document.getElementById('downloadPdf');
    const btnLabel = btn?.querySelector('span') || btn;
    const origText = btnLabel?.textContent;
    if (btn) { btn.style.opacity = '0.6'; btn.style.pointerEvents = 'none'; }
    if (btnLabel) btnLabel.textContent = 'Generando...';

    // Intentar cargar logo en el momento de generar (HTTP funciona en localhost y GitHub Pages)
    if (!PDF_LOGO_B64) await initPdfLogo();

    try {
        const { jsPDF } = window.jspdf;
        const products = window.DISTRIFEL_PRODUCTS || [];

        // ── Ordenar: orden explícito de tipos para PDF ──
        const TYPE_ORDER = {
            'regulador':       0,
            'flexible':        1,
            'membrana':        2,
            'llave-gas':       3,
            'canilla':         4,
            'accesorio':       5,
            'aislante':        6,
            'bronce-roscado':    7,
            'bronce-trefilado':  8,
            'fusion':            9,
            'hidro-bronce':      10,
            'gabinete':          11,
            'pilar':             12,
            'flotante':          13,
            'fuelle':            14,
            'montura':           15,
            'puerta':            16,
            'sopapa':            17,
            'reja':              18,
            'tapa':              19,
            'soda-caustica':     20,
            'terraja':           21,
            'tubo':              22,
            'valvula':           23,
            'malla-advertencia': 24,
        };
        const sorted = [...products].sort((a, b) => {
            const oa = TYPE_ORDER[a.type] ?? 99;
            const ob = TYPE_ORDER[b.type] ?? 99;
            if (oa !== ob) return oa - ob;
            if (oa === 99) return (TYPE_LABELS[a.type] || a.type).localeCompare(TYPE_LABELS[b.type] || b.type, 'es');
            return a.title.localeCompare(b.title, 'es');
        });


        // ── Helper: captura img del DOM (ya cargada por el browser, sin CORS) ──
        function imgFromDOM(pid, url) {
            // Buscar en cards del catálogo
            const card = document.querySelector(`[data-pid="${pid}"] .card-image img`);
            if (card && card.complete && card.naturalWidth > 0) {
                try {
                    const c = document.createElement('canvas');
                    const MAX = 300;
                    const sc = Math.min(MAX / card.naturalWidth, MAX / card.naturalHeight, 1);
                    c.width = card.naturalWidth * sc; c.height = card.naturalHeight * sc;
                    const ctx = c.getContext('2d');
                    ctx.fillStyle = '#f8fafc'; ctx.fillRect(0,0,c.width,c.height);
                    ctx.drawImage(card, 0, 0, c.width, c.height);
                    return c.toDataURL('image/jpeg', 0.75);
                } catch {}
            }
            return null;
        }

        // ── Precargar imágenes de productos y logos de marcas ──
        const imgCache = {};
        const brandsDone = new Set();
        await Promise.all([
            ...sorted.map(async p => {
                // Primero intentar desde DOM (funciona en file://)
                imgCache[p.id] = imgFromDOM(p.id, p.image) || await loadImgBase64(p.image, true, 300, 300);
                // Logo de marca (solo una vez por marca)
                if (p.brand && !brandsDone.has(p.brand)) {
                    brandsDone.add(p.brand);
                    const src = window.BRAND_LOGOS?.[p.brand];
                    if (src) imgCache['brand_' + p.brand] = await loadImgBase64(src, true, 200, 70);
                }
            })
        ]);

        // ── Constantes de layout ──
        const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
        const W = 210, H = 297;
        const M = 12;
        const HEADER_H = 26;
        const FOOTER_H = 18;
        const CONTENT_TOP = HEADER_H + 4;
        const CONTENT_BOT = H - FOOTER_H;

        const IMG_SIZE = 26;
        const LEFT_W = 76;
        const TEXT_X = M + IMG_SIZE + 5;
        const TEXT_W = LEFT_W - IMG_SIZE - 5;  // ~45mm
        const DIVIDER_X = M + LEFT_W + 4;
        const TABLE_X = DIVIDER_X + 5;
        const TABLE_W = W - TABLE_X - M;

        // Colores
        const NAVY      = [17, 24, 39];
        const TEAL      = [74, 159, 142];
        const WHITE     = [255, 255, 255];
        const GRAY      = [156, 163, 175];
        const DARK      = [31, 41, 55];
        const LIGHT     = [248, 250, 252];
        const GRAY_LINE = [220, 225, 230];

        const dateFile = new Date().toISOString().slice(0, 10);

        // ── Helper: calcular rowH ──
        const VAR_ROW = 9; // altura de cada fila de variante en mm
        function calcRowH(p) {
            const variants = p.variants || [];
            const displayRows = variants.length > 1 ? Math.ceil(variants.length / 2) : variants.length;
            return Math.max(IMG_SIZE + 16, 19 + displayRows * VAR_ROW + 6);
        }

        // Páginas por tipo — el contenido arranca en pág 3 (portada=1, índice=2)
        // (se calcula aquí, después de que CONTENT_TOP/CONTENT_BOT/IMG_SIZE ya están definidos)
        const typePageMap = computeTypePages(sorted, 3);

        // ── Helper: pre-calcular página inicial por tipo (para el índice) ──
        function computeTypePages(productList, startPage) {
            const map = {}, SH = 11, SP = 6;
            let page = startPage, y = CONTENT_TOP, lastType = null;
            for (const p of productList) {
                const rh = calcRowH(p);
                if (p.type !== lastType) {
                    if (lastType !== null && y + SP + SH + 8 + rh > CONTENT_BOT) { page++; y = CONTENT_TOP; }
                    if (!(p.type in map)) map[p.type] = page;
                    y += SP + SH + 8;
                    lastType = p.type;
                }
                if (y + rh > CONTENT_BOT) { page++; y = CONTENT_TOP; }
                y += rh + 2;
            }
            return map;
        }

        // ── Helper: dibujar header de página ──
        function addPageHeader(pageNum, isFirstPage) {
            // Fondo dark navy completo
            doc.setFillColor(...NAVY);
            doc.rect(0, 0, W, HEADER_H, 'F');

            // Logo blanco directo sobre fondo dark
            if (PDF_LOGO_B64) {
                try {
                    doc.addImage(PDF_LOGO_B64, 'PNG', M, 8, 44, 10.4);
                } catch (_e) {
                    doc.setFont('helvetica', 'bold');
                    doc.setFontSize(18);
                    doc.setTextColor(...WHITE);
                    doc.text('DISTRIFEL', M, 20);
                }
            } else {
                doc.setFont('helvetica', 'bold');
                doc.setFontSize(18);
                doc.setTextColor(...WHITE);
                doc.text('DISTRIFEL', M, 20);
            }

            // Título a la derecha blanco
            doc.setFont('helvetica', 'bold');
            doc.setFontSize(22);
            doc.setTextColor(...WHITE);
            doc.text('LISTA DE PRECIOS', W - M, 13, { align: 'right' });

            // Una sola línea: "Lista 116 • Actualizada: 29/04/2026"
            doc.setFont('helvetica', 'normal');
            doc.setFontSize(10);
            doc.setTextColor(...TEAL);
            doc.text('Lista 118  •  Actualizada: 13/05/2026', W - M, 19, { align: 'right' });

        }

        // ── Helper: footer gris con info de contacto ──
        function addPageFooter(pageNum) {
            const fy = H - FOOTER_H;
            const fh = FOOTER_H;
            const fcx = fy + fh / 2; // centro vertical del footer

            // Fondo gris clarito
            doc.setFillColor(245, 246, 248);
            doc.rect(0, fy, W, fh, 'F');
            doc.setFillColor(220, 225, 232);
            doc.rect(0, fy, W, 0.3, 'F');

            // Tarjeta blanca redondeada con borde sutil
            const cx = 4, cy = fy + 2, cw = W - 8, ch = fh - 4;
            doc.setFillColor(255, 255, 255);
            doc.setDrawColor(220, 225, 232);
            doc.setLineWidth(0.25);
            doc.roundedRect(cx, cy, cw, ch, 2, 2, 'FD');

            // Helpers para íconos simples
            const ic = [31, 41, 55]; // dark navy
            const textY = fy + fh / 2 + 1.5;
            doc.setTextColor(...ic);
            doc.setFont('helvetica', 'normal');
            doc.setFontSize(8);

            // Items del footer: 65% izquierdo (igual que antes)
            const items = [
                { label: '11 6463-9441',               icon: 'phone' },
                { label: 'ventas@distrifel.com',        icon: 'email' },
                { label: 'www.distrifel.com.ar',        icon: 'globe' },
            ];
            const footerLeft = 10;
            const footerRight = W - 8;
            const usableW = footerRight - footerLeft;
            const itemSlot = usableW * 0.65 / 3;

            items.forEach((item, i) => {
                const ix = footerLeft + i * itemSlot + 3;
                const iy = fy + fh / 2;
                const ty = iy + 1.5;

                doc.setDrawColor(...ic);
                doc.setLineWidth(0.45);

                if (item.icon === 'phone') {
                    // Celular: rect redondeado pequeño
                    doc.roundedRect(ix - 1.5, iy - 2.8, 3, 5, 0.6, 0.6, 'D');
                    doc.setLineWidth(0.8);
                    doc.line(ix - 0.8, iy + 1.2, ix + 0.8, iy + 1.2); // botón home
                } else if (item.icon === 'email') {
                    // Sobre: rect + V
                    doc.setLineWidth(0.45);
                    doc.rect(ix - 2.5, iy - 1.5, 5, 3.5, 'D');
                    doc.line(ix - 2.5, iy - 1.5, ix, iy + 0.5);
                    doc.line(ix, iy + 0.5, ix + 2.5, iy - 1.5);
                } else {
                    // Globo: círculo + líneas
                    doc.circle(ix, iy, 2.5, 'D');
                    doc.line(ix - 2.5, iy, ix + 2.5, iy);
                    doc.ellipse(ix, iy, 1.1, 2.5, 'D');
                }

                doc.setFont('helvetica', 'normal');
                doc.setFontSize(9);
                doc.setTextColor(...ic);
                const lines = item.label.split('\n');
                if (lines.length > 1) {
                    doc.text(lines[0], ix + 4, ty - 2);
                    doc.text(lines[1], ix + 4, ty + 3);
                } else {
                    doc.text(item.label, ix + 4, ty);
                }
            });

            // Número de página — círculo al 68% para dejar espacio al disclaimer
            const pgCX = W * 0.68, pgCY = fy + fh / 2, pgR = 5;
            doc.setFillColor(...TEAL);
            doc.circle(pgCX, pgCY, pgR, 'F');
            doc.setDrawColor(220, 225, 232);
            doc.setLineWidth(0.5);
            doc.circle(pgCX, pgCY, pgR, 'D');
            doc.setFont('helvetica', 'bold');
            doc.setFontSize(11);
            doc.setTextColor(255, 255, 255);
            doc.text(String(pageNum), pgCX, pgCY + 1.5, { align: 'center' });

            // Disclaimer — bien a la derecha, separado del círculo
            doc.setFont('helvetica', 'normal');
            doc.setFontSize(7);
            doc.setTextColor(...GRAY);
            const dix = W - M - 2;
            doc.text('Precios en pesos argentinos.', dix, pgCY - 1, { align: 'right' });
            doc.text('Sujetos a cambio sin previo aviso.', dix, pgCY + 3.5, { align: 'right' });

        }

        // ── Helper: dibujar separador de tipo ──
        function drawTypeSeparator(label, yPos) {
            doc.setFont('helvetica', 'bold');
            doc.setFontSize(8.5);
            const textW = doc.getTextWidth(label);
            const pillPad = 10;
            const pillH = 8;
            const pillW = textW + pillPad * 2;
            const cx = W / 2;
            const pillX = cx - pillW / 2;
            const lineY = yPos + pillH / 2 + 1;

            // Líneas negras
            doc.setDrawColor(40, 40, 40);
            doc.setLineWidth(0.4);
            doc.line(M, lineY, pillX - 4, lineY);
            doc.line(pillX + pillW + 4, lineY, W - M, lineY);

            // Pill blanco con borde negro
            doc.setFillColor(...WHITE);
            doc.setDrawColor(40, 40, 40);
            doc.setLineWidth(0.4);
            doc.roundedRect(pillX, yPos + 1, pillW, pillH, 2, 2, 'FD');

            // Texto negro
            doc.setTextColor(20, 20, 20);
            doc.text(label, cx, yPos + 6.8, { align: 'center' });
        }

        // Tamaños de logo por marca (base: 22×9). Solo listar las que difieren.
        const LOGO_SIZES = {
            canplast:    { w: 33, h:  8 },  // +15% ancho, -5% alto
            alarsa:      { w: 23, h:  9 },  // +5% ancho
            smartfix:    { w: 28, h: 13 },  // +25% ancho, +40% alto
            duke:        { w: 20, h:  8 },  // -10%
            aislatech:   { w: 24, h: 10 },  // +10%
            latynfusion: { w: 27, h: 12 },  // +25% general
            valforte:    { w: 23, h:  9 },  // +5% ancho
            covertex:    { w: 24, h:  7 },  // +10% ancho, -22% alto
        };

        // ── Helper: ícono por tipo ──
        function drawTypeIcon(type, cx, cy, sz) {
            const IB = [12, 22, 40];
            doc.setFillColor(...IB);
            doc.roundedRect(cx, cy, sz, sz, 2.5, 2.5, 'F');

            // Usar imagen PNG si está disponible
            const iconB64 = window.INDEX_ICONS_B64?.[type];
            if (iconB64) {
                const pad = 1;
                try { doc.addImage(iconB64, 'PNG', cx + pad, cy + pad, sz - pad * 2, sz - pad * 2); } catch {}
                return;
            }
            doc.setDrawColor(255, 255, 255);
            doc.setFillColor(255, 255, 255);
            const mx = cx + sz / 2, my = cy + sz / 2, r = sz * 0.22;
            const lw = (v) => doc.setLineWidth(v);
            lw(0.5);
            switch (type) {
                case 'regulador': {
                    doc.circle(mx, my + 0.8, r, 'D');
                    lw(0.45);
                    doc.line(mx, my + 0.8, mx + r * 0.6 * Math.cos(-2.2), my + 0.8 + r * 0.6 * Math.sin(-2.2));
                    lw(0.42);
                    [-2.6, -1.57, -0.54].forEach(a => doc.line(mx + (r - 1.5) * Math.cos(a), my + 0.8 + (r - 1.5) * Math.sin(a), mx + r * Math.cos(a), my + 0.8 + r * Math.sin(a)));
                    break;
                }
                case 'flexible': {
                    lw(0.45);
                    for (let j = 0; j < 10; j++) {
                        const t1 = j / 10, t2 = (j + 1) / 10;
                        doc.line(cx + 1 + t1 * (sz - 2), my + sz * 0.24 * Math.sin(t1 * Math.PI * 2.5), cx + 1 + t2 * (sz - 2), my + sz * 0.24 * Math.sin(t2 * Math.PI * 2.5));
                    }
                    break;
                }
                case 'membrana': {
                    [-sz*0.18, 0, sz*0.18].forEach(dy => doc.roundedRect(cx + 2, my + dy - 1, sz - 4, 2, 0.5, 0.5, 'F'));
                    break;
                }
                case 'llave-gas': {
                    doc.circle(cx + sz * 0.34, my - 0.5, r * 0.65, 'D');
                    doc.line(cx + sz * 0.34 + r * 0.65, my - 0.5, cx + sz - 2, my - 0.5);
                    doc.line(cx + sz - 2, my - 0.5, cx + sz - 2, my + sz * 0.16);
                    doc.line(cx + sz - 3.5, my - 0.5, cx + sz - 3.5, my + sz * 0.12);
                    break;
                }
                case 'canilla': {
                    doc.rect(cx + sz*0.12, my - sz*0.42, sz*0.76, 1.8, 'F');
                    doc.rect(cx + sz*0.43, my - sz*0.42, sz*0.22, sz*0.65, 'F');
                    doc.rect(cx + sz*0.43 + sz*0.22 - 1.8, my - sz*0.1, 1.8, sz*0.38, 'F');
                    break;
                }
                case 'accesorio': {
                    lw(0.5);
                    doc.circle(cx + sz*0.34, cy + sz*0.34, r * 0.6, 'D');
                    lw(1.1);
                    doc.line(cx + sz*0.34 + r*0.6*0.71, cy + sz*0.34 + r*0.6*0.71, cx + sz - 2, cy + sz - 2);
                    break;
                }
                case 'aislante': {
                    lw(0.45);
                    doc.ellipse(mx, my, r, r * 0.45, 'D');
                    [-r*0.22, 0, r*0.22].forEach(dy => doc.line(mx - r, my + dy, mx + r, my + dy));
                    break;
                }
                case 'bronce-roscado': {
                    lw(0.42);
                    doc.circle(mx, my, r, 'D');
                    doc.circle(mx, my, r * 0.52, 'D');
                    for (let a = 0; a < Math.PI * 2; a += Math.PI / 4)
                        doc.line(mx + r*0.52*Math.cos(a), my + r*0.52*Math.sin(a), mx + r*Math.cos(a), my + r*Math.sin(a));
                    break;
                }
                case 'fusion': {
                    doc.rect(cx + 1, my - 2.2, sz - 2, 4.4, 'F');
                    doc.setFillColor(...IB); doc.rect(cx + sz*0.38, my - 3.8, 3.5, 7.6, 'F');
                    doc.setFillColor(255, 255, 255); lw(0.5);
                    doc.roundedRect(cx + sz*0.38, my - 3.8, 3.5, 7.6, 0.5, 0.5, 'D');
                    break;
                }
                case 'hidro-bronce': {
                    doc.rect(cx + 1, my - 2, sz * 0.52, 4, 'F');
                    doc.rect(cx + sz*0.52 - 2, cy + 1, 4, my - cy + 2, 'F');
                    break;
                }
                case 'gabinete': {
                    lw(0.42); doc.roundedRect(cx+2, cy+2, sz-4, sz-4, 1, 1, 'D');
                    doc.line(cx + 2 + (sz-4)/2, cy + 2, cx + 2 + (sz-4)/2, cy + sz - 2);
                    doc.circle(cx + 2 + (sz-4)/2 - 2, my, 1, 'F');
                    doc.circle(cx + 2 + (sz-4)/2 + 2, my, 1, 'F');
                    break;
                }
                case 'pilar': {
                    doc.rect(cx + sz*0.18, cy + 2, sz*0.64, 2, 'F');
                    doc.rect(cx + sz*0.38, cy + 4, sz*0.24, sz - 8, 'F');
                    doc.rect(cx + sz*0.18, cy + sz - 4, sz*0.64, 2, 'F');
                    break;
                }
                case 'flotante': {
                    lw(0.45); doc.circle(cx + sz*0.38, cy + sz*0.38, r * 0.68, 'D');
                    doc.line(cx + sz*0.38 + r*0.68*0.71, cy + sz*0.38 + r*0.68*0.71, cx + sz - 2, cy + sz - 2);
                    break;
                }
                case 'fuelle': {
                    doc.rect(mx - 1.2, cy + 1, 2.4, sz * 0.22, 'F');
                    doc.rect(cx + sz*0.15, cy + sz*0.22, sz*0.7, sz*0.16, 'F');
                    doc.rect(cx + sz*0.22, cy + sz*0.38, sz*0.56, sz*0.16, 'F');
                    doc.rect(cx + sz*0.3, cy + sz*0.54, sz*0.4, sz*0.16, 'F');
                    doc.rect(mx - 1.2, cy + sz*0.7, 2.4, sz*0.18, 'F');
                    break;
                }
                case 'montura': {
                    lw(0.52);
                    doc.line(cx + 2, cy + sz - 3, cx + 2, my + 1);
                    doc.line(cx + sz - 2, cy + sz - 3, cx + sz - 2, my + 1);
                    for (let j = 0; j < 10; j++) {
                        const a1 = Math.PI + j * Math.PI / 10, a2 = Math.PI + (j+1) * Math.PI / 10;
                        doc.line(mx + r*1.1*Math.cos(a1), my + 1 + r*0.55*Math.sin(a1), mx + r*1.1*Math.cos(a2), my + 1 + r*0.55*Math.sin(a2));
                    }
                    doc.line(cx + 2, cy + sz - 3, cx + sz - 2, cy + sz - 3);
                    break;
                }
                case 'puerta': {
                    lw(0.45); doc.roundedRect(cx+3, cy+2, sz-6, sz-4, 1, 1, 'D');
                    doc.circle(cx + sz - 6.5, my + 1, 1.3, 'F');
                    break;
                }
                case 'sopapa': {
                    doc.rect(cx + sz*0.38, cy + sz*0.12, sz*0.24, sz*0.56, 'F');
                    doc.rect(cx + sz*0.12, cy + sz*0.6, sz*0.76, sz*0.2, 'F');
                    break;
                }
                case 'reja': {
                    lw(0.5); doc.roundedRect(cx+2, cy+2, sz-4, sz-4, 1, 1, 'D');
                    [1/3, 2/3].forEach(f => {
                        doc.line(cx + sz*f, cy + 2, cx + sz*f, cy + sz - 2);
                        doc.line(cx + 2, cy + sz*f, cx + sz - 2, cy + sz*f);
                    });
                    break;
                }
                case 'tapa': {
                    lw(0.52); doc.ellipse(mx, my + sz*0.12, r, r*0.32, 'D');
                    for (let j = 0; j < 10; j++) {
                        const a1 = Math.PI + j*Math.PI/10, a2 = Math.PI + (j+1)*Math.PI/10;
                        doc.line(mx + r*Math.cos(a1), my + sz*0.12 + r*0.32*Math.sin(a1), mx + r*Math.cos(a2), my + sz*0.12 + r*0.32*Math.sin(a2));
                    }
                    doc.line(mx - r, my + sz*0.12, mx + r, my + sz*0.12);
                    break;
                }
                case 'soda-caustica': {
                    lw(0.5);
                    for (let j = 0; j < 10; j++) {
                        const a1 = Math.PI + j*Math.PI/10, a2 = Math.PI + (j+1)*Math.PI/10;
                        doc.line(mx + r*Math.cos(a1), my + r*Math.sin(a1), mx + r*Math.cos(a2), my + r*Math.sin(a2));
                    }
                    doc.line(mx - r, my, mx, cy + 2.5);
                    doc.line(mx + r, my, mx, cy + 2.5);
                    break;
                }
                case 'terraja': {
                    lw(0.45);
                    for (let j = 0; j < 6; j++) {
                        const a1 = j*Math.PI/3 - Math.PI/6, a2 = (j+1)*Math.PI/3 - Math.PI/6;
                        doc.line(mx + r*Math.cos(a1), my + r*Math.sin(a1), mx + r*Math.cos(a2), my + r*Math.sin(a2));
                    }
                    doc.circle(mx, my, r*0.44, 'D');
                    break;
                }
                case 'tubo': {
                    lw(0.5);
                    doc.circle(mx, my, r, 'D');
                    doc.circle(mx, my, r*0.48, 'D');
                    break;
                }
                case 'valvula': {
                    doc.rect(cx + 1, my - 2, sz - 2, 4, 'F');
                    lw(0.45);
                    doc.setFillColor(...IB); doc.circle(mx, cy + sz*0.3, r*0.68, 'FD');
                    doc.setFillColor(255,255,255);
                    for (let a = 0; a < Math.PI; a += Math.PI/3)
                        doc.line(mx + r*0.68*Math.cos(a), cy+sz*0.3 + r*0.68*Math.sin(a), mx - r*0.68*Math.cos(a), cy+sz*0.3 - r*0.68*Math.sin(a));
                    doc.rect(mx - 1.2, cy + sz*0.3 + r*0.68, 2.4, sz*0.18, 'F');
                    break;
                }
                default: { lw(0.5); doc.circle(mx, my, r, 'D'); }
            }
        }

        // ── Helper: dibujar página de índice ──
        function drawIndexPage(tpMap) {
            const PW = 210, PH = 297;
            const TC = [74, 159, 142];    // teal
            const NV = [15, 24, 40];      // navy
            const LT = [248, 250, 253];   // light bg

            // ── Franja header dark navy ──────────────────────
            doc.setFillColor(...NV);
            doc.rect(0, 0, PW, 46, 'F');

            // Fondo blanco resto de página
            doc.setFillColor(255, 255, 255);
            doc.rect(0, 46, PW, PH - 46, 'F');

            // Watermark muy sutil en la zona blanca
            doc.setFont('helvetica', 'bold');
            doc.setFontSize(180);
            doc.setTextColor(...TC);
            doc.setGState(new doc.GState({ opacity: 0.03 }));
            doc.text('2026', PW / 2, PH / 2 + 50, { align: 'center' });
            doc.setGState(new doc.GState({ opacity: 1 }));

            // ── Encabezado (sobre dark) ──────────────────────
            doc.setFont('helvetica', 'bold');
            doc.setFontSize(8);
            doc.setTextColor(...TC);
            doc.text('DISTRIBUIDORA MAYORISTA  ·  LISTA 117', 18, 14);

            // Título: "ÍNDICE DE" blanco + "PRODUCTOS" teal
            doc.setFont('helvetica', 'bold');
            doc.setFontSize(28);
            doc.setTextColor(255, 255, 255);
            doc.text('ÍNDICE DE', 18, 30);
            const idxDeW = doc.getTextWidth('ÍNDICE DE ');
            doc.setTextColor(...TC);
            doc.text('PRODUCTOS', 18 + idxDeW, 30);

            // Logo derecha — sobre dark
            if (PDF_LOGO_B64) {
                try { doc.addImage(PDF_LOGO_B64, 'PNG', PW - 43, 19, 31, 9.2); } catch {}
            }

            // Línea teal bajo título
            doc.setFillColor(...TC);
            doc.rect(18, 34, 72, 1, 'F');

            // Borde inferior del header (sombra sutil)
            doc.setFillColor(220, 230, 240);
            doc.rect(0, 46, PW, 0.5, 'F');

            // ── Lista ────────────────────────────────────────
            const IDX_ORDER = [
                'regulador','flexible','membrana','llave-gas','canilla',
                'accesorio','aislante','bronce-roscado','fusion','hidro-bronce',
                'gabinete','pilar','flotante','fuelle','montura','puerta',
                'sopapa','reja','tapa','soda-caustica','terraja','tubo','valvula'
            ];
            const entries = IDX_ORDER
                .filter(t => tpMap[t])
                .map(t => ({ type: t, label: (TYPE_LABELS[t] || t).toUpperCase(), page: tpMap[t] }));

            const ICON_S = 13;
            const ROW_H  = 15;
            const COL_W  = (PW - 36 - 8) / 2;
            const MX     = 18;
            const COL2X  = MX + COL_W + 8;
            const HDR_Y  = 56;
            const LST_Y  = 66;

            // Headers de columna — más grandes, con línea teal
            [MX, COL2X].forEach(hx => {
                doc.setFont('helvetica', 'bold');
                doc.setFontSize(9);
                doc.setTextColor(...TC);
                doc.text('SECCIÓN', hx + ICON_S + 4, HDR_Y);
                doc.text('PÁG.', hx + COL_W - 6, HDR_Y, { align: 'right' });
                doc.setFillColor(...TC);
                doc.setGState(new doc.GState({ opacity: 0.4 }));
                doc.rect(hx + ICON_S + 4, HDR_Y + 1.5, COL_W - ICON_S - 10, 0.5, 'F');
                doc.setGState(new doc.GState({ opacity: 1 }));
            });

            entries.forEach((entry, i) => {
                const col = i % 2;
                const row = Math.floor(i / 2);
                const cx  = col === 0 ? MX : COL2X;
                const cy  = LST_Y + row * ROW_H;

                // Fondo alternado muy sutil (gris muy claro)
                if (row % 2 === 0) {
                    doc.setFillColor(245, 248, 252);
                    doc.rect(cx, cy, COL_W, ROW_H, 'F');
                }

                // Ícono
                drawTypeIcon(entry.type, cx + 1, cy + (ROW_H - ICON_S) / 2, ICON_S);

                // Nombre — dark navy sobre blanco
                doc.setFont('helvetica', 'bold');
                doc.setFontSize(10.5);
                doc.setTextColor(...NV);
                doc.text(entry.label, cx + ICON_S + 5, cy + ROW_H / 2 + 1.8);

                // Número — más grande, teal
                const pg = String(entry.page).padStart(2, '0');
                doc.setFont('helvetica', 'bold');
                doc.setFontSize(14);
                doc.setTextColor(...TC);
                doc.text(pg, cx + COL_W - 13, cy + ROW_H / 2 + 2.5, { align: 'right' });

                // Flecha — imagen PNG
                if (window.ARROW_CIRCLE_B64) {
                    const arrowS = 5.5;
                    try { doc.addImage(window.ARROW_CIRCLE_B64, 'PNG', cx + COL_W - arrowS - 0.5, cy + ROW_H / 2 - arrowS / 2, arrowS, arrowS); } catch {}
                }

                // Link clicable sobre toda la fila → va a la página del tipo
                doc.link(cx, cy, COL_W, ROW_H, { pageNumber: entry.page });

                // Separador sutil entre filas
                doc.setFillColor(220, 228, 238);
                doc.rect(cx, cy + ROW_H - 0.3, COL_W, 0.3, 'F');
            });

            // ── Tip box ─────────────────────────────────────
            const rows  = Math.ceil(entries.length / 2);
            const tipY  = LST_Y + rows * ROW_H + 8;
            const tipH  = 22;
            const tipW  = PW - 36;
            const divX  = MX + tipW * 0.62;   // divisor izquierda/derecha

            // Fondo light + borde teal sutil
            doc.setFillColor(240, 247, 245);
            doc.setDrawColor(...TC);
            doc.setGState(new doc.GState({ opacity: 0.45 }));
            doc.setLineWidth(0.35);
            doc.roundedRect(MX, tipY, tipW, tipH, 3, 3, 'FD');
            doc.setGState(new doc.GState({ opacity: 1 }));

            // Divisor vertical
            doc.setDrawColor(...TC);
            doc.setGState(new doc.GState({ opacity: 0.25 }));
            doc.setLineWidth(0.3);
            doc.line(divX, tipY + 3, divX, tipY + tipH - 3);
            doc.setGState(new doc.GState({ opacity: 1 }));

            // ── Lado izquierdo: Consejo ──
            if (PDF_ICON_B64) {
                try { doc.addImage(PDF_ICON_B64, 'PNG', MX + 4, tipY + tipH/2 - 5.5, 11, 11); } catch {}
            } else {
                doc.setFillColor(...TC);
                doc.circle(MX + 10, tipY + tipH / 2, 5.5, 'F');
                doc.setFont('helvetica', 'bold');
                doc.setFontSize(8.5);
                doc.setTextColor(255, 255, 255);
                doc.text('i', MX + 10, tipY + tipH / 2 + 2, { align: 'center' });
            }

            doc.setFont('helvetica', 'bold');
            doc.setFontSize(9);
            doc.setTextColor(...TC);
            doc.text('CONSEJO', MX + 18, tipY + 8);
            doc.setFont('helvetica', 'normal');
            doc.setFontSize(9);
            doc.setTextColor(...NV);
            doc.text('Usá los marcadores del PDF o hacé clic en\ncada categoría para navegar rápidamente.', MX + 18, tipY + 14, { maxWidth: divX - MX - 20 });

            // ── Lado derecho: QR ──
            const qrX  = divX + 4;
            const qrY  = tipY + 3;
            const qrS  = tipH - 6;   // tamaño del QR ~16mm

            if (PDF_QR_B64) {
                try { doc.addImage(PDF_QR_B64, 'PNG', qrX, qrY, qrS, qrS); } catch {}
            }

            // Texto derecho
            const txtX = qrX + qrS + 3;
            doc.setFont('helvetica', 'bold');
            doc.setFontSize(8);
            doc.setTextColor(...NV);
            doc.text('VER CATÁLOGO', txtX, tipY + 8);
            doc.text('COMPLETO ONLINE', txtX, tipY + 13);
            doc.setFont('helvetica', 'bold');
            doc.setFontSize(8.5);
            doc.setTextColor(...TC);
            doc.text('www.distrifel.com.ar', txtX, tipY + 18);

            // ── Footer contacto ──────────────────────────────
            doc.setFillColor(12, 18, 28);
            doc.rect(0, PH - 22, PW, 22, 'F');
            doc.setFont('helvetica', 'normal');
            doc.setFontSize(11);
            doc.setTextColor(156, 163, 175);
            doc.text('ventas@distrifel.com  |  www.distrifel.com.ar  |  11 6463-9441', PW / 2, PH - 9, { align: 'center' });
        }

        // ── Helper: dibujar row de producto ──
        function drawProductRow(p, yPos) {
            const variants = p.variants || [];
            const rowH = calcRowH(p);

            // Fondo blanco del row
            doc.setFillColor(...WHITE);
            doc.rect(M, yPos, W - M * 2, rowH, 'F');

            // Título — arriba del todo, ancho completo del panel izquierdo
            doc.setFont('helvetica', 'bold');
            doc.setFontSize(11);
            doc.setTextColor(...DARK);
            const titleLines2 = doc.splitTextToSize(p.title || '', LEFT_W);
            doc.text(titleLines2.slice(0, 2), M, yPos + 9);

            // Panel izquierdo: imagen con borde sutil (debajo del título)
            const imgY = yPos + 14;
            doc.setFillColor(248, 250, 252);
            doc.roundedRect(M, imgY, IMG_SIZE, IMG_SIZE, 1.5, 1.5, 'F');
            doc.setDrawColor(220, 226, 232);
            doc.setLineWidth(0.2);
            doc.roundedRect(M, imgY, IMG_SIZE, IMG_SIZE, 1.5, 1.5, 'D');

            const img64 = imgCache[p.id];
            if (img64) {
                try {
                    doc.addImage(img64, 'JPEG', M + 1, imgY + 1, IMG_SIZE - 2, IMG_SIZE - 2);
                } catch (_e) {}
            }

            // Logo de marca — grande y centrado en el espacio a la derecha de la imagen
            const brandB64 = (window.BRAND_LOGOS_B64 && p.brand) ? window.BRAND_LOGOS_B64[p.brand] : null;
            const logoAreaX = TEXT_X;
            const logoAreaW = DIVIDER_X - 4 - TEXT_X;
            const logoSize = LOGO_SIZES[p.brand] || { w: 22, h: 9 };
            const logoW = logoSize.w, logoH = logoSize.h;
            const logoX = logoAreaX + (logoAreaW - logoW) / 2;
            const logoY = imgY + (IMG_SIZE - logoH) / 2;
            if (brandB64) {
                const bFmt2 = brandB64.startsWith('data:image/png') ? 'PNG' : brandB64.startsWith('data:image/webp') ? 'WEBP' : 'JPEG';
                try { doc.addImage(brandB64, bFmt2, logoX, logoY, logoW, logoH); } catch {}
            } else if (p.brand) {
                const brandName2 = (window.BRAND_NAMES && window.BRAND_NAMES[p.brand]) || p.brand;
                doc.setFont('helvetica', 'bold');
                doc.setFontSize(9);
                doc.setTextColor(...TEAL);
                doc.text(brandName2.toUpperCase(), logoAreaX + logoAreaW / 2, imgY + IMG_SIZE / 2 + 1.5, { align: 'center' });
            }

            // Línea vertical divisoria gris
            doc.setDrawColor(...GRAY_LINE);
            doc.setLineWidth(0.3);
            doc.line(DIVIDER_X, yPos + 2, DIVIDER_X, yPos + rowH - 2);

            // Panel derecho — tabla
            // Header "OPCIONES" y "PRECIO"
            doc.setFont('helvetica', 'bold');
            doc.setFontSize(8.5);
            doc.setTextColor(...TEAL);
            doc.text('OPCIONES', TABLE_X + 2, yPos + 9);
            doc.text('PRECIO', TABLE_X + TABLE_W - 2, yPos + 9, { align: 'right' });

            // Línea teal bajo header de tabla
            doc.setFillColor(...TEAL);
            doc.rect(TABLE_X, yPos + 11, TABLE_W, 0.5, 'F');

            // Decidir si usar 2 sub-columnas (más de 6 variantes)
            const use2Cols = variants.length > 1;

            if (use2Cols) {
                const half = Math.ceil(variants.length / 2);
                const subColW = TABLE_W / 2 - 1;

                variants.forEach((v, i) => {
                    const colIdx = i < half ? 0 : 1;
                    const rowIdx = i < half ? i : i - half;
                    const subX = TABLE_X + colIdx * (subColW + 2);
                    const rowBg = rowIdx % 2 === 0 ? [241, 245, 249] : [255, 255, 255];

                    doc.setFillColor(...rowBg);
                    doc.rect(subX, yPos + 12 + rowIdx * VAR_ROW, subColW, VAR_ROW, 'F');

                    const varLabel = doc.splitTextToSize(v.desc || '-', subColW - 25)[0] || (v.desc || '-');
                    doc.setFont('helvetica', 'normal');
                    doc.setFontSize(10);
                    doc.setTextColor(...DARK);
                    doc.text(varLabel, subX + 2, yPos + 17.5 + rowIdx * VAR_ROW);

                    if (v.price === 0) {
                        doc.setTextColor(...GRAY);
                        doc.setFont('helvetica', 'normal');
                        doc.text('Sin stock', subX + subColW - 2, yPos + 17.5 + rowIdx * VAR_ROW, { align: 'right' });
                    } else {
                        doc.setFont('helvetica', 'bold');
                        doc.setTextColor(...TEAL);
                        doc.text(formatPrice(v.price), subX + subColW - 2, yPos + 17.5 + rowIdx * VAR_ROW, { align: 'right' });
                    }
                });

                // Línea divisoria sutil entre columnas
                const divX = TABLE_X + subColW + 1;
                doc.setDrawColor(210, 220, 228);
                doc.setLineWidth(0.25);
                doc.line(divX, yPos + 12, divX, yPos + 12 + half * VAR_ROW);
            } else {
                variants.forEach((v, i) => {
                    const rowBg = i % 2 === 0 ? [241, 245, 249] : [255, 255, 255];
                    doc.setFillColor(...rowBg);
                    doc.rect(TABLE_X, yPos + 12 + i * VAR_ROW, TABLE_W, VAR_ROW, 'F');

                    const varLabel = doc.splitTextToSize(v.desc || '-', TABLE_W - 35)[0] || (v.desc || '-');
                    doc.setFont('helvetica', 'normal');
                    doc.setFontSize(10);
                    doc.setTextColor(...DARK);
                    doc.text(varLabel, TABLE_X + 2, yPos + 17.5 + i * VAR_ROW);

                    if (v.price === 0) {
                        doc.setTextColor(...GRAY);
                        doc.setFont('helvetica', 'normal');
                        doc.text('Sin stock', TABLE_X + TABLE_W - 2, yPos + 17.5 + i * VAR_ROW, { align: 'right' });
                    } else {
                        doc.setFont('helvetica', 'bold');
                        doc.setTextColor(...TEAL);
                        doc.text(formatPrice(v.price), TABLE_X + TABLE_W - 2, yPos + 17.5 + i * VAR_ROW, { align: 'right' });
                    }
                });
            }

            // Línea separadora entre productos (gris 0.3pt)
            doc.setDrawColor(...GRAY_LINE);
            doc.setLineWidth(0.3);
            doc.line(M, yPos + rowH, W - M, yPos + rowH);
        }

        // ── Paginación ──
        let pageNum = 1;

        // ══════════════════════════════════════════════
        // PORTADA — diseño tipográfico profesional
        // ══════════════════════════════════════════════
        {
            const PW = 210, PH = 297;

            // Imagen de fondo (caños industriales como el hero del sitio)
            if (typeof PDF_BG_B64 !== 'undefined' && PDF_BG_B64) {
                try { doc.addImage(PDF_BG_B64, 'JPEG', 0, 0, PW, PH); } catch {}
            }
            // Overlay dark 70% (más transparente → fondo de caños más visible)
            doc.setGState(new doc.GState({ opacity: 0.70 }));
            doc.setFillColor(17, 24, 39);
            doc.rect(0, 0, PW, PH, 'F');
            doc.setGState(new doc.GState({ opacity: 1 }));

            // ── "2026" watermark centrado en página ──
            doc.setFont('helvetica', 'bold');
            doc.setFontSize(160);
            doc.setTextColor(74, 159, 142);
            doc.setGState(new doc.GState({ opacity: 0.10 }));
            doc.text('2026', PW / 2, PH / 2 + 40, { align: 'center' });
            doc.setGState(new doc.GState({ opacity: 1 }));

            // ── Bloque central de contenido — centrado verticalmente ──
            const centerY = PH / 2 - 30;

            // "DISTRIBUIDORA MAYORISTA"
            doc.setFont('helvetica', 'normal');
            doc.setFontSize(16);
            doc.setTextColor(74, 159, 142);
            doc.text('DISTRIBUIDORA MAYORISTA', PW / 2, centerY - 28, { align: 'center' });

            // Logo
            if (PDF_LOGO_B64) {
                try {
                    const lw = 130, lh = 30.7;
                    doc.addImage(PDF_LOGO_B64, 'PNG', (PW - lw) / 2, centerY - 22, lw, lh);
                } catch {}
            } else {
                doc.setFont('helvetica', 'bold');
                doc.setFontSize(48);
                doc.setTextColor(255, 255, 255);
                doc.text('DISTRIFEL', PW / 2, centerY + 5, { align: 'center' });
            }

            // Separador teal
            doc.setFillColor(74, 159, 142);
            doc.rect(30, centerY + 16, PW - 60, 0.8, 'F');

            // "LISTA DE PRECIOS"
            doc.setFont('helvetica', 'bold');
            doc.setFontSize(28);
            doc.setTextColor(255, 255, 255);
            doc.text('LISTA DE PRECIOS', PW / 2, centerY + 32, { align: 'center' });

            // Tagline
            doc.setFont('helvetica', 'normal');
            doc.setFontSize(15);
            doc.setTextColor(156, 163, 175);
            doc.text('Ferretería · Sanitarios · Construcción', PW / 2, centerY + 46, { align: 'center' });

            // Separador
            doc.setFillColor(30, 42, 58);
            doc.rect(30, centerY + 52, PW - 60, 0.8, 'F');

            // Info lista
            doc.setFont('helvetica', 'normal');
            doc.setFontSize(13);
            doc.setTextColor(156, 163, 175);
            doc.text('Lista 118  •  Actualizada: 13/05/2026', PW / 2, centerY + 63, { align: 'center' });

            // ── Contacto al pie ──
            doc.setFillColor(12, 18, 28);
            doc.rect(0, PH - 22, PW, 22, 'F');
            doc.setFont('helvetica', 'normal');
            doc.setFontSize(11);
            doc.setTextColor(156, 163, 175);
            doc.text('ventas@distrifel.com  |  www.distrifel.com.ar  |  11 6463-9441', PW / 2, PH - 9, { align: 'center' });

            doc.addPage();
            pageNum++;
        }
        // ── Fin portada ──

        // ── Página 2: Índice ──
        drawIndexPage(typePageMap);

        doc.addPage();
        pageNum++;
        addPageHeader(pageNum, true);
        addPageFooter(pageNum);

        let y = CONTENT_TOP;
        let lastType = null;
        const SEP_H = 11;
        const SEP_PAD = 6;

        for (const p of sorted) {
            const rowH = calcRowH(p);

            // Separador de tipo — nueva página solo si separador + producto no entran
            if (p.type !== lastType) {
                const sepLabel = (TYPE_LABELS[p.type] || p.type).toUpperCase();

                if (lastType !== null && y + SEP_PAD + SEP_H + 8 + rowH > CONTENT_BOT) {
                    pageNum++;
                    doc.addPage();
                    addPageHeader(pageNum, false);
                    addPageFooter(pageNum);
                    y = CONTENT_TOP;
                }

                y += SEP_PAD;
                drawTypeSeparator(sepLabel, y);
                y += SEP_H + 8;
                lastType = p.type;
            }

            // Si el producto no cabe: nueva página
            if (y + rowH > CONTENT_BOT) {
                pageNum++;
                doc.addPage();
                addPageHeader(pageNum, false);
                addPageFooter(pageNum);
                y = CONTENT_TOP;
            }

            drawProductRow(p, y);
            y += rowH + 2;
        }

        // ── Guardar ──
        const now = new Date();
        const dd   = String(now.getDate()).padStart(2, '0');
        const mm   = String(now.getMonth() + 1).padStart(2, '0');
        const yyyy = now.getFullYear();
        doc.save(`Distrifel - Lista de Precios ${dd}-${mm}-${yyyy}.pdf`);

    } finally {
        if (btn) { btn.style.opacity = ''; btn.style.pointerEvents = ''; }
        if (btnLabel && origText) btnLabel.textContent = origText;
    }
}

// State
const state = {
    search: '',
    filters: {
        category: 'all',
        brand: new Set(),
        type: new Set()
    },
    discountActive: false
};

const PRICE_MARKUP = window.PRICE_MARKUP || 1.20;

function getDisplayPrice(rawPrice) {
    return state.discountActive ? rawPrice : Math.round(rawPrice * PRICE_MARKUP);
}

function checkClientDiscount(name) {
    const clients = window.DISCOUNT_CLIENTS || [];
    return clients.some(c => c === name.toLowerCase().trim());
}

function refreshAllPrices() {
    document.querySelectorAll('.product-card-v2').forEach(card => {
        const priceEl  = card.querySelector('.price-value');
        if (!priceEl) return;
        const raw = parseInt(priceEl.dataset.rawPrice);
        if (!raw) return;
        priceEl.textContent = formatPrice(getDisplayPrice(raw));
    });
}

