/**
 * Navigation Scroll Effect
 */
function initNavigation() {
    const navbar = document.querySelector('.navbar');
    if (!navbar) return;

    window.addEventListener('scroll', () => {
        navbar.classList.toggle('scrolled', window.scrollY > 100);
    });

    const hero = document.querySelector('.hero');
    const homeBtn = document.getElementById('navHomeBtn');
    if (!hero) return;

    let heroHidden = false;
    let savedHeroHeight = 0;

    const hideHero = () => {
        if (heroHidden) return;
        heroHidden = true;
        savedHeroHeight = hero.offsetHeight;
        const curY = window.scrollY;
        hero.style.display = 'none';
        // Compensar: el catálogo sube en el DOM, ajustar scroll para que el usuario
        // vea exactamente el mismo contenido que antes
        window.scrollTo({ top: curY - savedHeroHeight, behavior: 'instant' });
        document.body.classList.add('past-hero');
    };

    const showHero = () => {
        const scrollBeforeShow = window.scrollY; // capturar ANTES del layout change
        heroHidden = false;
        hero.style.display = '';
        document.body.classList.remove('past-hero');
        // Compensar: hero volvió, el contenido bajó savedHeroHeight → ajustar para mismo punto visual
        window.scrollTo({ top: scrollBeforeShow + savedHeroHeight, behavior: 'instant' });
        // Luego scroll suave al tope
        requestAnimationFrame(() => window.scrollTo({ top: 0, behavior: 'smooth' }));
    };

    // Ocultar cuando el hero fue completamente scrolleado fuera del viewport
    window.addEventListener('scroll', () => {
        if (!heroHidden && window.scrollY >= hero.offsetTop + hero.offsetHeight) {
            hideHero();
        }
    }, { passive: true });

    // Ocultar también al click en "Ver Catálogo" o en una marca del carousel
    document.addEventListener('click', (e) => {
        const trigger = e.target.closest('a[href="#catalogo"], .brand-btn');
        if (trigger && !heroHidden) {
            // Pequeño delay para que el scroll empiece antes de ocultar
            setTimeout(hideHero, 200);
        }
    });

    homeBtn?.addEventListener('click', (e) => {
        e.preventDefault();
        showHero();
    });
}

/**
 * Mobile Menu Toggle
 */
function initMobileMenu() {
    const navToggle = document.querySelector('.nav-toggle');
    const navMenu = document.querySelector('.nav-menu');
    
    if (!navToggle || !navMenu) return;
    
    navToggle.addEventListener('click', () => {
        navMenu.classList.toggle('open');
        navToggle.classList.toggle('open');
        document.body.style.overflow = navMenu.classList.contains('open') ? 'hidden' : '';
    });
    
    // Close menu when clicking a link
    navMenu.querySelectorAll('.nav-link').forEach(link => {
        link.addEventListener('click', () => {
            navMenu.classList.remove('open');
            navToggle.classList.remove('open');
            document.body.style.overflow = '';
        });
    });
    
    // Close on escape
    document.addEventListener('keydown', (e) => {
        if (e.key === 'Escape' && navMenu.classList.contains('open')) {
            navMenu.classList.remove('open');
            navToggle.classList.remove('open');
            document.body.style.overflow = '';
        }
    });
}

/**
 * Smooth Scroll
 */
function initSmoothScroll() {
    document.querySelectorAll('a[href^="#"]').forEach(anchor => {
        anchor.addEventListener('click', function(e) {
            const targetId = this.getAttribute('href');
            if (targetId === '#') return;
            
            const targetElement = document.querySelector(targetId);
            if (!targetElement) return;
            
            e.preventDefault();
            
            const navHeight = document.querySelector('.navbar')?.offsetHeight || 0;
            const targetPosition = targetElement.offsetTop - navHeight;
            
            window.scrollTo({
                top: targetPosition,
                behavior: 'smooth'
            });
        });
    });
}

/**
 * Search Functionality
 */
function initSearch() {
    const searchInput = document.getElementById('searchInput');
    const searchClear = document.getElementById('searchClear');
    
    if (!searchInput) return;
    
    // Search input handler with debounce
    let debounceTimer;
    searchInput.addEventListener('input', (e) => {
        clearTimeout(debounceTimer);
        debounceTimer = setTimeout(() => {
            state.search = e.target.value.toLowerCase().trim();
            filterProducts();
            
            // Show/hide clear button
            searchClear.classList.toggle('visible', state.search.length > 0);
        }, 200);
    });
    
    // Clear search
    searchClear.addEventListener('click', () => {
        searchInput.value = '';
        state.search = '';
        searchClear.classList.remove('visible');
        filterProducts();
        searchInput.focus();
    });
    
    // Focus search on Ctrl/Cmd + K
    document.addEventListener('keydown', (e) => {
        if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
            e.preventDefault();
            searchInput.focus();
            searchInput.select();
        }
    });
}

/**
 * Filter Sidebar — always-visible lists (no dropdowns)
 */
function initFilters() {
    const clearFiltersBtn = document.getElementById('clearFilters');
    const resetFiltersBtn = document.getElementById('resetFilters');

    // Event delegation: un solo listener para todos los .filter-option,
    // incluyendo los generados dinámicamente por buildTypeFilter
    document.getElementById('filterSidebar')?.addEventListener('click', e => {
        const option = e.target.closest('.filter-option');
        if (!option) return;
        const menu = option.closest('.filter-menu');
        if (!menu) return;
        const filterType = menu.dataset.menu;
        const value = option.dataset.value;
        const label = option.dataset.label || option.textContent.trim();

        if (filterType === 'brand' || filterType === 'type') {
            const set = state.filters[filterType];
            if (value === 'all') {
                set.clear();
                menu.querySelectorAll('.filter-option').forEach(o => o.classList.remove('active'));
                option.classList.add('active');
            } else {
                menu.querySelector('[data-value="all"]')?.classList.remove('active');
                if (set.has(value)) { set.delete(value); option.classList.remove('active'); }
                else                { set.add(value);    option.classList.add('active');    }
                if (set.size === 0) menu.querySelector('[data-value="all"]')?.classList.add('active');
            }
            const badgeLabel = set.size === 0 ? '' : set.size === 1 ? label : `${set.size} seleccionados`;
            updateAccordionBadge(filterType, set.size === 0 ? 'all' : value, badgeLabel);
        } else {
            state.filters[filterType] = value;
            menu.querySelectorAll('.filter-option').forEach(o => o.classList.remove('active'));
            option.classList.add('active');
            updateAccordionBadge(filterType, value, label);
            option.closest('.accordion-section')?.classList.remove('expanded');
        }

        filterProducts();
    });

    const clearAll = () => {
        state.search = '';
        state.filters = { category: 'all', brand: new Set(), type: new Set() };

        const searchInput = document.getElementById('searchInput');
        const searchClear = document.getElementById('searchClear');
        if (searchInput) searchInput.value = '';
        if (searchClear) searchClear.classList.remove('visible');

        document.querySelectorAll('.filter-option').forEach(opt => {
            opt.classList.toggle('active', opt.dataset.value === 'all');
        });

        document.querySelectorAll('.category-chips .chip').forEach(c => {
            c.classList.toggle('active', c.dataset.category === 'all');
        });

        // Reset accordion badges a "Todas"/"Todos"
        ['brand', 'type', 'category'].forEach(t => updateAccordionBadge(t, 'all', ''));

        filterProducts();
    };

    if (clearFiltersBtn) clearFiltersBtn.addEventListener('click', clearAll);
    if (resetFiltersBtn) resetFiltersBtn.addEventListener('click', clearAll);
}

/**
 * Filter Sidebar — toggle en desktop + drawer en mobile
 */
function initFilterSidebar() {
    const layout = document.querySelector('.catalog-layout');
    const sidebar = document.getElementById('filterSidebar');
    const overlay = document.getElementById('sidebarOverlay');
    const toggleBtn = document.getElementById('filterToggleBtn');
    const closeBtn = document.getElementById('sidebarClose');

    const isMobile = () => window.innerWidth < 1024;

    const updateToggleLabel = () => {
        const labelEl = toggleBtn?.querySelector('.filter-toggle-label');
        if (!labelEl) return;
        if (isMobile()) {
            labelEl.textContent = 'Filtros';
            toggleBtn.classList.remove('is-collapsed');
        } else {
            const collapsed = layout?.classList.contains('sidebar-collapsed');
            labelEl.textContent = collapsed ? 'Mostrar filtros' : 'Ocultar filtros';
            toggleBtn.classList.toggle('is-collapsed', collapsed);
        }
    };

    const open = () => {
        if (isMobile()) {
            sidebar?.classList.add('open');
            overlay?.classList.add('visible');
            document.body.classList.add('sidebar-open');
        } else {
            layout?.classList.remove('sidebar-collapsed');
        }
        updateToggleLabel();
    };

    const close = () => {
        if (isMobile()) {
            sidebar?.classList.remove('open');
            overlay?.classList.remove('visible');
            document.body.classList.remove('sidebar-open');
        } else {
            layout?.classList.add('sidebar-collapsed');
        }
        updateToggleLabel();
    };

    const toggle = () => {
        if (isMobile()) {
            sidebar?.classList.contains('open') ? close() : open();
        } else {
            layout?.classList.contains('sidebar-collapsed') ? open() : close();
        }
    };

    // "Ver X productos" cierra el sheet en mobile
    document.getElementById('sheetApplyBtn')?.addEventListener('click', close);

    toggleBtn?.addEventListener('click', toggle);
    closeBtn?.addEventListener('click', close);
    overlay?.addEventListener('click', close);
    window.addEventListener('resize', updateToggleLabel);
    updateToggleLabel();

    document.addEventListener('keydown', (e) => {
        if (e.key === 'Escape' && (sidebar?.classList.contains('open') || layout?.classList.contains('sidebar-collapsed') === false)) {
            close();
        }
    });
}

/**
 * Sidebar accordion — toggle + badge con filtro activo
 */
function initAccordion() {
    document.querySelectorAll('.accordion-header').forEach(header => {
        header.addEventListener('click', () => {
            header.closest('.accordion-section')?.classList.toggle('expanded');
        });
    });
    ['category', 'type', 'brand'].forEach(t => updateAccordionBadge(t, 'all', ''));
}

const ACCORDION_DEFAULTS = { category: 'Todas', brand: 'Todas', type: 'Todos' };

function updateAccordionBadge(filterType, value, label) {
    const badge = document.querySelector(`.accordion-badge[data-section="${filterType}"]`);
    if (!badge) return;
    const isDefault = (value === 'all' || !value);
    badge.textContent = isDefault ? ACCORDION_DEFAULTS[filterType] : label;
    badge.classList.toggle('is-default', isDefault);
    badge.classList.toggle('is-active', !isDefault);
}

/**
 * Filter Products
 */
function filterProducts() {
    const products = document.querySelectorAll('.product-card, .product-card-v2');
    const noResults = document.getElementById('noResults');
    const productsGrid = document.getElementById('productsGrid');
    let visibleCount = 0;
    
    products.forEach(product => {
        const category = product.dataset.category;
        const brand = product.dataset.brand;
        const type = product.dataset.type;
        const name = product.dataset.name || '';
        
        // Check filters
        const matchesCategory = state.filters.category === 'all' || category === state.filters.category;
        const matchesBrand = state.filters.brand.size === 0 || state.filters.brand.has(brand);
        const matchesType  = state.filters.type.size  === 0 || state.filters.type.has(type);
        
        // Check search
        const matchesSearch = state.search === '' || 
            name.includes(state.search) ||
            category.includes(state.search) ||
            brand.includes(state.search) ||
            type.includes(state.search);
        
        const isVisible = matchesCategory && matchesBrand && matchesType && matchesSearch;
        const wasHidden = product.classList.contains('hidden');

        product.classList.toggle('hidden', !isVisible);

        if (isVisible && wasHidden) {
            product.classList.remove('filter-reveal');
            void product.offsetWidth; // reflow para reiniciar animación
            product.classList.add('filter-reveal');
        }
        
        if (isVisible) visibleCount++;
    });
    
    // Ocultar separadores si no hay productos visibles de ese tipo
    document.querySelectorAll('.catalog-type-divider').forEach(div => {
        const type = div.dataset.type;
        const hasVisible = [...document.querySelectorAll(`.product-card-v2:not(.hidden)[data-type="${type}"]`)].length > 0;
        div.classList.toggle('hidden', !hasVisible);
    });

    // Update counter
    const resultsCount = document.getElementById('resultsCount');
    if (resultsCount) resultsCount.textContent = visibleCount;

    // Update "Ver X productos" en el bottom sheet
    const sheetCount = document.getElementById('sheetCount');
    if (sheetCount) sheetCount.textContent = visibleCount;

    // Show/hide no results message
    if (noResults) noResults.classList.toggle('visible', visibleCount === 0);
    if (productsGrid) productsGrid.style.display = visibleCount === 0 ? 'none' : '';

    updateActiveFiltersBar();
}

function updateActiveFiltersBar() {
    const bar   = document.getElementById('activeFiltersBar');
    const badge = document.getElementById('filterCountBadge');
    if (!bar) return;

    const active = [];

    if (state.filters.category !== 'all') {
        const el    = document.querySelector(`.category-chips .chip[data-category="${state.filters.category}"] span:last-child`);
        const label = el?.textContent.trim() || state.filters.category;
        active.push({ key: 'category', value: state.filters.category, label });
    }
    state.filters.brand.forEach(b => {
        const el    = document.querySelector(`[data-menu="brand"] [data-value="${b}"]`);
        const label = el?.dataset.label || el?.textContent.trim() || b;
        active.push({ key: 'brand', value: b, label });
    });
    state.filters.type.forEach(t => {
        const el    = document.querySelector(`[data-menu="type"] [data-value="${t}"]`);
        const label = el?.dataset.label || el?.textContent.trim() || t;
        active.push({ key: 'type', value: t, label });
    });
    if (state.search) {
        active.push({ key: 'search', value: state.search, label: `"${state.search}"` });
    }

    const clearAllHTML = active.length > 1
        ? `<button class="active-filter-chip clear-all-chip" id="clearAllChip" type="button">× Limpiar todo</button>`
        : '';

    bar.innerHTML = active.map(f => `
        <button class="active-filter-chip" data-key="${f.key}" data-value="${f.value}" type="button">
            ${f.label}
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" width="11" height="11" aria-hidden="true">
                <line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>
            </svg>
        </button>
    `).join('') + clearAllHTML;

    bar.classList.toggle('has-filters', active.length > 0);

    bar.querySelectorAll('.active-filter-chip').forEach(chip => {
        chip.addEventListener('click', () => {
            const { key, value } = chip.dataset;
            if (key === 'search') {
                state.search = '';
                const inp = document.getElementById('searchInput');
                const clr = document.getElementById('searchClear');
                if (inp) inp.value = '';
                if (clr) clr.classList.remove('visible');
            } else if (key === 'brand' || key === 'type') {
                state.filters[key].delete(value);
                document.querySelector(`[data-menu="${key}"] [data-value="${value}"]`)?.classList.remove('active');
                if (state.filters[key].size === 0) {
                    document.querySelector(`[data-menu="${key}"] [data-value="all"]`)?.classList.add('active');
                    updateAccordionBadge(key, 'all', '');
                } else {
                    const rem      = state.filters[key].size;
                    const firstVal = [...state.filters[key]][0];
                    const firstLbl = document.querySelector(`[data-menu="${key}"] [data-value="${firstVal}"]`)?.textContent.trim() || firstVal;
                    updateAccordionBadge(key, 'multi', rem === 1 ? firstLbl : `${rem} seleccionados`);
                }
            } else {
                state.filters[key] = 'all';
                document.querySelectorAll(`[data-menu="${key}"] .filter-option`).forEach(o =>
                    o.classList.toggle('active', o.dataset.value === 'all')
                );
                if (key === 'category') {
                    document.querySelectorAll('.category-chips .chip').forEach(c =>
                        c.classList.toggle('active', c.dataset.category === 'all')
                    );
                }
                updateAccordionBadge(key, 'all', '');
            }
            filterProducts();
        });
    });

    // Limpiar todo
    document.getElementById('clearAllChip')?.addEventListener('click', () => {
        state.search = '';
        state.filters = { category: 'all', brand: new Set(), type: new Set() };
        document.querySelectorAll('.filter-option').forEach(o => o.classList.toggle('active', o.dataset.value === 'all'));
        document.querySelectorAll('.category-chips .chip').forEach(c => c.classList.toggle('active', c.dataset.category === 'all'));
        ['brand', 'type', 'category'].forEach(t => updateAccordionBadge(t, 'all', ''));
        const inp = document.getElementById('searchInput');
        const clr = document.getElementById('searchClear');
        if (inp) inp.value = '';
        if (clr) clr.classList.remove('visible');
        filterProducts();
    });

    // Badge en botón Filtros (excluye búsqueda de texto)
    const count = active.filter(f => f.key !== 'search').length;
    if (badge) {
        badge.textContent = count > 0 ? count : '';
        badge.classList.toggle('visible', count > 0);
    }
}

