function buildTypeFilter(category) {
    const menu = document.getElementById('typeFilterMenu');
    if (!menu) return;

    const products = window.DISTRIFEL_PRODUCTS || [];

    // Tipos disponibles para la categoría seleccionada
    const types = [...new Set(
        products
            .filter(p => category === 'all' || p.category === category)
            .map(p => p.type)
            .filter(Boolean)
    )].sort((a, b) => (TYPE_LABELS[a] || a).localeCompare(TYPE_LABELS[b] || b));

    // Marcar activos los tipos que siguen seleccionados
    const activeTypes = state.filters.type;
    menu.innerHTML = `<button class="filter-option${activeTypes.size === 0 ? ' active' : ''}" data-value="all" data-label="Todos">Todos</button>` +
        types.map(t =>
            `<button class="filter-option${activeTypes.has(t) ? ' active' : ''}" data-value="${escapeHtml(t)}" data-label="${escapeHtml(TYPE_LABELS[t] || t)}">${escapeHtml(TYPE_LABELS[t] || t)}</button>`
        ).join('');

    // Eliminar tipos activos que ya no existen en la nueva lista
    [...activeTypes].forEach(t => {
        if (!types.includes(t)) activeTypes.delete(t);
    });
    if (activeTypes.size === 0) updateAccordionBadge('type', 'all', '');
}

function escapeHtml(str) {
    return String(str || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function placeholderImg(title) {
    const txt = encodeURIComponent((title || 'Producto').slice(0, 20));
    return `https://placehold.co/400x300/f0fdf9/2d8a78?text=${txt}`;
}

function renderProducts() {
    const container = document.getElementById('productsGrid');
    const products = window.DISTRIFEL_PRODUCTS;
    if (!container || !Array.isArray(products)) return;

    container.innerHTML = '';

    const TYPE_ORDER = { regulador: 0, flexible: 1, membrana: 2, 'llave-gas': 3 };
    const sorted = [...products].sort((a, b) => {
        const oa = TYPE_ORDER[a.type] ?? 99;
        const ob = TYPE_ORDER[b.type] ?? 99;
        if (oa !== ob) return oa - ob;
        if (oa === 99) {
            const ta = TYPE_LABELS[a.type] || a.type;
            const tb = TYPE_LABELS[b.type] || b.type;
            const tc = ta.localeCompare(tb, 'es');
            if (tc !== 0) return tc;
        }
        return a.title.localeCompare(b.title, 'es');
    });

    const fragment = document.createDocumentFragment();
    let lastType = null;

    for (const p of sorted) {
        // Separador por tipo
        if (p.type !== lastType) {
            const sep = document.createElement('div');
            sep.className = 'catalog-type-divider';
            sep.dataset.type = p.type;
            const label = TYPE_LABELS[p.type] || p.type;
            sep.innerHTML = `<span class="catalog-type-divider-label">${escapeHtml(label)}</span>`;
            fragment.appendChild(sep);
            lastType = p.type;
        }

        const card = document.createElement('article');
        card.className = 'product-card-v2';
        card.dataset.category = p.category || 'otros';
        card.dataset.brand = p.brand || '';
        card.dataset.type = p.type || '';
        card.dataset.name = p.searchName || p.title.toLowerCase();
        card.dataset.pid = p.id;

        // Prices
        const prices = p.variants.map(v => v.price).filter(n => n > 0);
        const firstPrice = p.variants[0]?.price || 0;
        const minPrice = prices.length ? Math.min(...prices) : 0;
        const maxPrice = prices.length ? Math.max(...prices) : 0;
        const showDesde = prices.length > 1 && minPrice !== maxPrice;

        // Mostrar todas las variantes (sin truncar con "···")
        let variantsHtml = '';
        const hasVariantLabels = p.variants.some(v => v.desc);
        if (p.variants.length >= 1 && hasVariantLabels) {
            const vItems = p.variants.map((v, idx) => {
                const label = v.desc || v.code || 'Único';
                const oos = !v.price ? ' out-of-stock' : '';
                return `<span class="card-variant${idx === 0 ? ' selected' : ''}${oos}" data-price="${v.price || 0}" data-code="${escapeHtml(v.code)}">${escapeHtml(label)}</span>`;
            }).join('');

            variantsHtml = `<div class="card-variants">${vItems}</div>`;
        }

        const firstOutOfStock = !firstPrice;
        const allOutOfStock = !prices.length;
        if (allOutOfStock) card.dataset.outOfStock = 'true';
        if (p.iva) card.dataset.iva = p.iva;

        // Image
        const imgSrc = p.image || placeholderImg(p.title);
        const fallback = placeholderImg(p.title);

        // Category tag
        const tagClass = CATEGORY_TAG_CLASS[p.category] || 'tag-otros';
        const tagLabel = CATEGORY_LABELS[p.category] || 'Otros';

        // Brand (only show logo if we have it locally)
        const brandHtml = (p.brand && BRAND_LOGOS[p.brand])
            ? `<div class="card-brand"><img src="${BRAND_LOGOS[p.brand]}" alt="${escapeHtml(p.brand)}"></div>`
            : '';

        const brandName = p.brand ? (BRAND_NAMES[p.brand] || p.brand) : '';

        card.innerHTML = `
            <div class="card-header">
                ${brandHtml}
            </div>
            <div class="card-content">
                <div class="card-image">
                    <img src="${imgSrc}" alt="${escapeHtml(p.title)}" loading="lazy" onerror="this.onerror=null;this.src='${fallback}';">
                </div>
                <div class="card-list-meta">
                    ${brandName ? `<span class="card-brand-name">${escapeHtml(brandName)}</span>` : ''}
                </div>
                <h3 class="card-title">${escapeHtml(p.title)}</h3>
                ${variantsHtml}
                <div class="card-price">
                    ${firstOutOfStock
                        ? '<span class="price-no-stock">Sin stock</span>'
                        : `${showDesde ? '<span class="price-from">desde</span>' : ''}<span class="price-value" data-raw-price="${firstPrice}">${formatPrice(getDisplayPrice(firstPrice))}</span>`
                    }
                </div>
            </div>
        `;

        fragment.appendChild(card);
    }

    container.appendChild(fragment);

    // Update initial results count
    const resultsCount = document.getElementById('resultsCount');
    if (resultsCount) resultsCount.textContent = products.length;
}

